<!DOCTYPE html>
<html>
<head>
    <title>Test Profile Picture Integration</title>
</head>
<body>
    <h1>Profile Picture Integration Test</h1>
    <button onclick="testGoogleLogin\(\)">Test Google Login Response</button>
    <pre id="output"></pre>

    <script>
        async function testGoogleLogin\(\) {
            const output = document.getElementById\('output'\);

            // Check if user data in localStorage has profilePictureUrl
            const authStorage = localStorage.getItem\('auth-storage'\);
            const user = localStorage.getItem\('user'\);

            output.textContent = 'Auth Storage:\\n' + JSON.stringify\(JSON.parse\(authStorage || '{}'\), null, 2\);
            output.textContent += '\\n\\nUser:\\n' + JSON.stringify\(JSON.parse\(user || '{}'\), null, 2\);

            // Check if the user object has profilePictureUrl
            const userObj = JSON.parse\(user || '{}'\);
            if \(userObj.profilePictureUrl\) {
                output.textContent += '\\n\\n✅ Profile Picture URL found: ' + userObj.profilePictureUrl;
            } else {
                output.textContent += '\\n\\n❌ Profile Picture URL NOT found in user object';
            }
        }
    </script>
</body>
</html>
EOF)

