// Run this in browser console \(F12\) to clear old data and force fresh login

// Clear all auth-related data
localStorage.removeItem\('user'\);
localStorage.removeItem\('auth-storage'\);
localStorage.removeItem\('tenantId'\);

// Clear all cookies \(for httpOnly token refresh\)
document.cookie.split\(";"\).forEach\(function\(c\) { 
    document.cookie = c.replace\(/^ +/, ""\).replace\(/=.*/, "=;expires=" + new Date\(\).toUTCString\(\) + ";path=/"\); 
}\);

console.log\("✅ Cleared all auth data. Please refresh and log in again."\);
alert\("Auth data cleared! Refresh the page and log in with Google to get your profile picture."\);

// Reload the page
setTimeout\(\(\) => window.location.href = '/auth/login', 1000\);
